import React, { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { WS } from "./../utils/websocket";
import yardsQDG from "./../utils/yardsQDG";
import trainsQDG from "./../utils/trainsQDG";
import yardsDJZ from "./../utils/yardsDJZ";
import trainsDJZ from "./../utils/trainsDJZ";
import typeOptions from "./../utils/types";
import sportsOptions from "./../utils/sports";
import PasswordModal from "./PsdModal";
import {
  Cascader,
  Form,
  Select,
  Input,
  Button,
  Space,
  Flex,
  Popconfirm,
  Switch,
  message,
} from "antd";

const tailLayout = {
  wrapperCol: { offset: 10, span: 16 },
};
const tailLayoutF = {
  wrapperCol: { offset: 6, span: 16 },
};

const setYardsOptions = (yards) => {
  return yards.map((yard) => ({
    value: yard.label,
    label: yard.label,
    children: yard.children.map((lane) => ({
      value: lane.label,
      label: lane.label,
      rawData: lane.value,
    })),
  }));
};

const setTrainsOptions = (trains) => {
  return trains.map((train) => ({
    value: train.label,
    label: train.label,
    children: train.children.map((lane) => ({
      value: lane.label,
      label: lane.label,
      rawData: lane.value,
    })),
  }));
};

