const SendPoints = () => {
  const autoDrivingCars = useSelector(
    (state) => state.sendPoint.autoDrivingCars
  );
  const fasAebSwitch = useSelector((state) => state.sendPoint.fasAebSwitch);
  const [type, setType] = useState("DEFAULT");
  const [blacklistedLane, setBlacklistedLane] = useState("");
  const [curTrainOption, setCurTrainOption] = useState([]);
  const [curYardOption, setCurYardOption] = useState([]);
  const [trainOption, setTrainOptions] = useState(null);
  const [yardOption, setYardOptions] = useState(null);
  const [visible, setVisible] = useState(false);
  const [adjustmentDistance, setAdjustmentDistance] = useState(0);
  const [sport, setSport] = useState(null);
  const [curTrains, setCurTrains] = useState([]);
  const [curYards, setCurYards] = useState([]);

  useEffect(() => {
    if (sport === "QDG") {
      setCurYards(setYardsOptions(yardsQDG));
      setCurTrains(setTrainsOptions(trainsQDG));
      setTrainOptions(null);
      setYardOptions(null);
      setCurTrainOption([]);
      setCurYardOption([]);
    } else if (sport === "DJZ") {
      setCurYards(setYardsOptions(yardsDJZ));
      setCurTrains(setTrainsOptions(trainsDJZ));
      setTrainOptions(null);
      setYardOptions(null);
      setCurTrainOption([]);
      setCurYardOption([]);
    }
  }, [sport]);

  const confirmArrive = (e) => {
    WS.requestImmediatelyArrived();
    message.success("Click on Yes");
  };

  const cancelArrive = (e) => {
    message.warning("Click on No");
  };

  const confirmCircle = (e) => {
    const start = {
      x: autoDrivingCars.positionX,
      y: autoDrivingCars.positionY,
      z: 0,
    };
    const start_heading = autoDrivingCars.heading;
    WS.requestRoute(
      start,
      start_heading,
      [],
      start,
      null,
      "isOneClickLoopRunning"
    );
    message.success("Click on Yes");
  };

  const cancelCircle = (e) => {
    message.warning("Click on No");
  };

  const handleAutoFasAebSwitch = (checked) => {
    if (fasAebSwitch) {
      setVisible(!checked);
    } else {
      WS.changeFASAEBStatus(true, null);
    }
  };

  const handleOk = (pwd) => {
    WS.changeFASAEBStatus(false, pwd);
    setVisible(false);
  };

  const handleCancel = () => {
    setVisible(false);
  };

  const onSendYard = () => {
    if (!yardOption) {
      return message.error("Please select a yard");
    }
    const start = {
      x: autoDrivingCars.positionX,
      y: autoDrivingCars.positionY,
      z: 0,
    };
    const start_heading = autoDrivingCars.heading;
    WS.sendDemonstrateRequest(
      start,
      start_heading,
      yardOption,
      type,
      blacklistedLane
    );
  };

  const onSendTrain = () => {
    if (!trainOption) {
      return message.error("Please select a train");
    }
    const start = {
      x: autoDrivingCars.positionX,
      y: autoDrivingCars.positionY,
      z: 0,
    };
    const start_heading = autoDrivingCars.heading;
    WS.sendDemonstrateRequest(
      start,
      start_heading,
      trainOption,
      type,
      blacklistedLane
    );
  };

  return (
    <div>
      <Flex gap="middle" justify="center" vertical>
        <Flex gap="middle" justify="center">
          <Popconfirm
            title="Immediately arrive at the station"
            description="Are you sure immediately arrive at the station?"
            onConfirm={confirmArrive}
            onCancel={cancelArrive}
            okText="Yes"
            cancelText="No"
          >
            <Button type="primary" size="large">
              Immediately arrive at the station
            </Button>
          </Popconfirm>
          <Popconfirm
            title="Start running circle test"
            description="Are you sure start running circle test?"
            onConfirm={confirmCircle}
            onCancel={cancelCircle}
            okText="Yes"
            cancelText="No"
          >
            <Button type="primary" size="large">
              Start running loop test
            </Button>
          </Popconfirm>
        </Flex>
        <Flex gap="middle" justify="center">
          <Switch
            checkedChildren="1"
            unCheckedChildren="0"
            checked={fasAebSwitch}
            onChange={handleAutoFasAebSwitch}
          />
          <label>FAS-AEB</label>
        </Flex>
        <PasswordModal
          visible={visible}
          onOk={handleOk}
          onCancel={handleCancel}
        />
        <Flex gap="middle" justify="center">
          <Form
            labelCol={{ span: 4 }}
            wrapperCol={{ span: 20 }}
            layout="horizontal"
            size={"large"}
            style={{ width: 800, marginTop: 20 }}
          >
            <Form.Item label="Distance">
              <Input
                type="number"
                min={0}
                step={0.1}
                placeholder="Please enter adjustment distance"
                value={adjustmentDistance}
                onChange={(e) =>
                  setAdjustmentDistance(parseFloat(e.target.value))
                }
              />
            </Form.Item>
            <Form.Item {...tailLayoutF}>
              <Space>
                <Button
                  type="primary"
                  htmlType="submit"
                  onClick={() =>
                    WS.fineTuningRequest(
                      "TINY_ADJUSTMENT_FRONT",
                      adjustmentDistance
                    )
                  }
                >
                  TINY_ADJUSTMENT_FRONT
                </Button>
                <Button
                  type="primary"
                  htmlType="button"
                  onClick={() =>
                    WS.fineTuningRequest(
                      "TINY_ADJUSTMENT_BACK",
                      adjustmentDistance
                    )
                  }
                >
                  TINY_ADJUSTMENT_BACK
                </Button>
              </Space>
            </Form.Item>
            <Form.Item label="Type">
              <Select
                options={typeOptions}
                defaultValue={type}
                onChange={(value) => {
                  setType(value);
                }}
              ></Select>
            </Form.Item>
            <Form.Item label="Blacklisted">
              <Input
                placeholder="Please enter IDs separated by commas"
                value={blacklistedLane}
                onChange={(e) => setBlacklistedLane(e.target.value)}
              />
            </Form.Item>
            <Form.Item label="Sport">
              <Select
                options={sportsOptions}
                value={sport}
                onChange={(value) => {
                  setSport(value);
                }}
              />
            </Form.Item>
            <Form.Item label="Yard">
              <Cascader
                options={curYards}
                value={curYardOption}
                onChange={(value, selectedOptions) => {
                  if (value) {
                    setYardOptions(
                      selectedOptions[selectedOptions.length - 1].rawData
                    );
                    setCurYardOption(value);
                  } else {
                    setYardOptions(null);
                    setYardOptions([]);
                  }
                }}
              />
            </Form.Item>
            <Form.Item
              label="Train"
              style={{ display: sport === "DJZ" ? "none" : "block" }}
            >
              <Cascader
                options={curTrains}
                value={curTrainOption}
                onChange={(value, selectedOptions) => {
                  if (value) {
                    setTrainOptions(
                      selectedOptions[selectedOptions.length - 1].rawData
                    );
                    setCurTrainOption(value);
                  } else {
                    setTrainOptions(null);
                    setTrainOptions([]);
                  }
                }}
              />
            </Form.Item>
            <Form.Item {...tailLayout}>
              <Space>
                <Button type="primary" htmlType="submit" onClick={onSendYard}>
                  Send Yard
                </Button>
                <Button type="primary" htmlType="button" onClick={onSendTrain}>
                  Send Train
                </Button>
              </Space>
            </Form.Item>
          </Form>
        </Flex>
      </Flex>
    </div>
  );
};

export default SendPoints;
